import java.util.PriorityQueue

class SegmentTreeMin(size: Int) {
  private val n: Int = {
    var s = 1
    while (s < size) s <<= 1
    s
  }
  private val tree: Array[Long] = Array.fill(2 * n)(Long.MaxValue)

  def update(index: Int, value: Long): Unit = {
    var idx = index + n
    tree(idx) = math.min(tree(idx), value)
    while (idx > 1) {
      idx >>= 1
      tree(idx) = math.min(tree(2 * idx), tree(2 * idx + 1))
    }
  }

  def query(l: Int, r: Int): Long = {
    var left = l + n
    var right = r + n
    var res = Long.MaxValue
    while (left <= right) {
      if ((left & 1) == 1) {
        res = math.min(res, tree(left))
        left += 1
      }
      if ((right & 1) == 0) {
        res = math.min(res, tree(right))
        right -= 1
      }
      left >>= 1
      right >>= 1
    }
    res
  }
}

