def solve(grid: Array[Array[Long]], k: Long): Long = {
    val m = grid.length
    val n = grid(0).length
    val maxK = k.toInt
    val INF = Long.MaxValue

    val teleportList = Array.ofDim[Array[(Int, Int)]](m, n)
    for (i <- 0 until m; j <- 0 until n) {
        val v0 = grid(i)(j)
        val list = mutable.ArrayBuffer[(Int, Int)]()
        for (x <- 0 until m; y <- 0 until n) {
            if (grid(x)(y) <= v0) {
                list += ((x, y))
            }
        }
        teleportList(i)(j) = list.toArray
    }

    val dp = Array.fill(m, n, maxK + 1)(INF)
    val pq = mutable.PriorityQueue.empty[(Long, Int, Int, Int)](Ordering.by(-_._1))

    dp(0)(0)(0) = 0
    pq.enqueue((0L, 0, 0, 0))

    while (pq.nonEmpty) {
        val (cost, i, j, t) = pq.dequeue()
        if (cost != dp(i)(j)(t)) {
        } else {
            val moves = List((0, 1), (1, 0))
            for ((di, dj) <- moves) {
                val ni = i + di
                val nj = j + dj
                if (ni < m && nj < n) {
