            if (t < maxK) {
                for ((x, y) <- teleportList(i)(j)) {
                    if (cost < dp(x)(y)(t + 1)) {
                        dp(x)(y)(t + 1) = cost
                        pq.enqueue((cost, x, y, t + 1))
                    }
                }
            }
        }
    }

    (0 to maxK).map(t => dp(m - 1)(n - 1)(t)).min
}
